      {/* --- COMORBIDITY & RISK ALERT SECTION --- */}
      {(settings.comorbidities.length > 0 || hasHistoryRisk) && (
          <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-red-100 dark:border-red-900/50 overflow-hidden">
