              {renderContent()}
            </div>
         </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Medicine, AppMode } from '../types';
import { Pill, Plus, Trash2, Check, ShieldAlert } from 'lucide-react';
import { Button } from './Button';
import { MedicineSafety } from './MedicineSafety';

interface Props {
  currentWeek?: number;
  isPostpartum?: boolean;
  mode?: AppMode; // New prop to determine specific list
}

export const MedicineTracker: React.FC<Props> = ({ currentWeek = 1, isPostpartum = false, mode = 'pregnant' }) => {
  const [activeTab, setActiveTab] = useState<'my-meds' | 'safety'>('my-meds');

  // Initialize with empty array or default, will be overwritten by useEffect load
  const [medicines, setMedicines] = useState<Medicine[]>([]);

  const [newMed, setNewMed] = useState({ name: '', time: '' });

  // Persistence Key based on mode
  const STORAGE_KEY = isPostpartum ? 'bloom_pp_medicines' : 'bloom_medicines';
  const DATE_KEY = STORAGE_KEY + '_date';

  // Load from Storage on Mount or Mode Change
  useEffect(() => {
    const loadMedicines = () => {
        const saved = localStorage.getItem(STORAGE_KEY);
        const lastDate = localStorage.getItem(DATE_KEY);
        const today = new Date().toISOString().split('T')[0];

        if (saved) {
            let parsed = JSON.parse(saved);

            // Check if it's a new day, if so reset 'taken' status
            if (lastDate !== today) {
                parsed = parsed.map((m: Medicine) => ({ ...m, taken: false }));
                // Update storage immediately with reset values
                localStorage.setItem(STORAGE_KEY, JSON.stringify(parsed));
                localStorage.setItem(DATE_KEY, today);
            }
            setMedicines(parsed);
        } else {
            // Default Medicines if nothing saved
            const defaults: Medicine[] = isPostpartum ? [
                { id: '1', name: 'Calcium', dosage: '500mg', frequency: 'BD', time: '09:00', taken: false },
                { id: '2', name: 'Iron', dosage: '100mg', frequency: 'OD', time: '20:00', taken: false }
            ] : [
                { id: '1', name: 'Folic Acid', dosage: '5mg', frequency: 'Daily', time: '09:00', taken: false },
                { id: '2', name: 'Iron Supplement', dosage: '100mg', frequency: 'Daily', time: '20:00', taken: false }
            ];
            setMedicines(defaults);
            // Save defaults immediately
            localStorage.setItem(STORAGE_KEY, JSON.stringify(defaults));
            localStorage.setItem(DATE_KEY, today);
        }
    };
    loadMedicines();
  }, [isPostpartum]);

  // Save to Storage whenever medicines change
  useEffect(() => {
      // Avoid saving empty array on initial render before load
      if (medicines.length > 0) {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(medicines));
          // Always update date key to today when saving
          localStorage.setItem(DATE_KEY, new Date().toISOString().split('T')[0]);
      }
  }, [medicines, STORAGE_KEY]);

  const toggleTaken = (id: string) => {
    setMedicines(prev => prev.map(m => m.id === id ? { ...m, taken: !m.taken } : m));
  };

  const addMed = () => {
    if (newMed.name && newMed.time) {
      setMedicines(prev => [...prev, {
        id: Date.now().toString(),
        name: newMed.name,
        time: newMed.time,
        dosage: 'Check label',
        frequency: 'Daily',
        taken: false
      }]);
      setNewMed({ name: '', time: '' });
    }
  };

  const removeMed = (id: string) => {
    setMedicines(prev => prev.filter(m => m.id !== id));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">
       <div className="flex gap-2 p-1 bg-gray-100 dark:bg-indigo-950/50 rounded-xl w-fit mx-auto mb-6">
          <button 
             onClick={() => setActiveTab('my-meds')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'my-meds' ? 'bg-white dark:bg-deep-card shadow text-teal-600 dark:text-teal-400' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             My Medicines
          </button>
          <button 
             onClick={() => setActiveTab('safety')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${activeTab === 'safety' ? 'bg-white dark:bg-deep-card shadow text-bloom-DEFAULT' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             <ShieldAlert size={16} /> {isPostpartum ? 'Lactation Safety' : 'Safety Guide'}
          </button>
       </div>

       {activeTab === 'my-meds' ? (
         <>
          <div className="bg-gradient-to-r from-teal-500 to-emerald-500 rounded-3xl p-8 text-white shadow-lg">
              <h2 className="text-2xl font-bold mb-2">Medicine Cabinet</h2>
              <p className="opacity-90">Keep track of your supplements and prescriptions. Compliance is key for a healthy {isPostpartum ? 'recovery' : 'pregnancy'}.</p>
          </div>

          <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
              <div className="p-6 border-b border-gray-100 dark:border-indigo-800">
                <h3 className="font-bold text-gray-800 dark:text-white text-lg">Daily Checklist</h3>
              </div>

              <div className="divide-y divide-gray-100 dark:divide-indigo-800">
                {medicines.map(med => (
                  <div key={med.id} className={`p-4 flex items-center justify-between transition-colors ${med.taken ? 'bg-green-50/50 dark:bg-green-900/10' : 'hover:bg-gray-50 dark:hover:bg-indigo-900/20'}`}>
                      <div className="flex items-center gap-4">
                        <button 
                            onClick={() => toggleTaken(med.id)}
                            className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${med.taken ? 'bg-green-500 border-green-500 text-white' : 'border-gray-300 dark:border-gray-600 text-transparent hover:border-green-500'}`}
                        >
                            <Check size={16} />
                        </button>
                        <div>
                            <p className={`font-medium text-lg ${med.taken ? 'text-gray-400 line-through' : 'text-gray-800 dark:text-white'}`}>
                                {med.name}
                            </p>
                            <p className="text-sm text-gray-500 dark:text-gray-400">
                                {med.time} • {med.dosage}
                            </p>
                        </div>
                      </div>
                      <button onClick={() => removeMed(med.id)} className="text-gray-400 hover:text-red-500 p-2">
                        <Trash2 size={18} />
                      </button>
                  </div>
                ))}

                {medicines.length === 0 && (
                    <div className="p-8 text-center text-gray-500">No medicines added yet.</div>
                )}
              </div>

              <div className="p-6 bg-gray-50 dark:bg-indigo-950/30">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Medicine Name</label>
                        <input 
                            type="text" 
                            value={newMed.name}
                            onChange={(e) => setNewMed({...newMed, name: e.target.value})}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900"
                            placeholder="e.g. Calcium"
                        />
                    </div>
                    <div className="w-full md:w-40">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Time</label>
                        <input 
                            type="time" 
                            value={newMed.time}
                            onChange={(e) => setNewMed({...newMed, time: e.target.value})}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900"
                        />
                    </div>
                    <Button onClick={addMed} className="w-full md:w-auto bg-teal-500 hover:bg-teal-600 hover:shadow-teal-500/30">
                        <Plus size={20} /> Add
                    </Button>
                </div>
              </div>
          </div>
         </>
       ) : (
         <MedicineSafety currentWeek={currentWeek} isPostpartum={isPostpartum} mode={mode} />
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { Search, ShieldCheck, AlertTriangle, XCircle, Info, ChevronDown, ChevronUp, Octagon, Key } from 'lucide-react';
import { checkMedicineSafety } from '../services/geminiService';
import { MedicineSafetyResult, AppMode } from '../types';
import { MEDICINE_DATABASE, ALWAYS_CONTRAINDICATED } from '../constants';

interface Props {
  currentWeek: number;
  isPostpartum: boolean;
  mode?: AppMode;
}

export const MedicineSafety: React.FC<Props> = ({ currentWeek, isPostpartum, mode = 'pregnant' }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<MedicineSafetyResult | null>(null);
  const [expandedCategory, setExpandedCategory] = useState<number | null>(0);
  const [showContraindicated, setShowContraindicated] = useState(false);
  const [missingKey, setMissingKey] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;
    setLoading(true);
    setMissingKey(false);

    try {
        // Determine context for AI
        const context = isPostpartum ? 'lactation' : 'pregnancy';
        const res = await checkMedicineSafety(searchTerm, currentWeek, context);
        setResult(res);
    } catch (err: any) {
        if (err.message === 'MISSING_API_KEY') {
            setMissingKey(true);
            setResult(null);
        }
    } finally {
        setLoading(false);
    }
  };

  // Logic for picking database based on profile mode
  let guideData;
  let trimesterTitle;

  if (mode === 'planning') {
      guideData = MEDICINE_DATABASE[0];
      trimesterTitle = "Pre-Conception / Planning";
  } else if (mode === 'postpartum') {
      guideData = MEDICINE_DATABASE[4];
      trimesterTitle = "Lactation / Postpartum";
  } else {
      // Pregnant
      const trimester = currentWeek <= 13 ? 1 : currentWeek <= 27 ? 2 : 3;
      guideData = MEDICINE_DATABASE[trimester] || MEDICINE_DATABASE[1];
      trimesterTitle = `Trimester ${trimester} (Week ${currentWeek})`;
  }

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'Safe': return 'bg-green-100 text-green-700 border-green-200 dark:bg-green-900/30 dark:text-green-300 dark:border-green-800';
      case 'Caution': return 'bg-yellow-100 text-yellow-700 border-yellow-200 dark:bg-yellow-900/30 dark:text-yellow-300 dark:border-yellow-800';
      case 'Unsafe': return 'bg-red-100 text-red-700 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-800';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getStatusIcon = (status: string) => {
    switch(status) {
      case 'Safe': return <ShieldCheck size={24} />;
      case 'Caution': return <AlertTriangle size={24} />;
      case 'Unsafe': return <XCircle size={24} />;
      default: return <Info size={24} />;
    }
  };

  const toggleCategory = (idx: number) => {
    setExpandedCategory(expandedCategory === idx ? null : idx);
  };

  return (
    <div className="space-y-8">
      {/* Search Section */}
      <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
        <h3 className="text-xl font-bold mb-4 text-gray-800 dark:text-white flex items-center gap-2">
            AI Safety Check
            {isPostpartum && <span className="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded-full">Lactation Focus</span>}
        </h3>
        <p className="text-sm text-gray-500 mb-4">
          Verify any specific medicine for {trimesterTitle}.
        </p>
        <form onSubmit={handleSearch} className="flex gap-2">
          <input 
            type="text" 
            placeholder="Enter medicine name (e.g. Ibuprofen)" 
            className="flex-1 px-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-gray-50 dark:bg-indigo-950/50 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-bloom-DEFAULT"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <Button type="submit" isLoading={loading}>
            <Search size={20} />
          </Button>
        </form>

        {missingKey && (
            <div className="mt-6 p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-xl flex items-center gap-3 border border-red-200 dark:border-red-800">
                <Key size={24} className="shrink-0" />
                <div>
                    <strong>AI Key Missing:</strong> To use AI safety checks, please add your Google Gemini API Key in your Profile.
                </div>
            </div>
        )}

        {result && (
          <div className={`mt-6 p-6 rounded-2xl border ${getStatusColor(result.status)} animate-fade-in`}>
             <div className="flex items-start gap-4">
                <div className="mt-1">{getStatusIcon(result.status)}</div>
                <div>
                   <h4 className="font-bold text-lg mb-1">{result.status}</h4>
                   <p className="mb-3 leading-relaxed">{result.description}</p>
                   {result.alternatives && result.alternatives.length > 0 && (
                     <div className="text-sm opacity-90">
                       <strong>Alternatives:</strong> {result.alternatives.join(', ')}
                     </div>
                   )}
                </div>
             </div>
          </div>
        )}
      </div>

       {/* Contraindicated List (Collapsible) */}
       <div className="bg-red-50 dark:bg-red-900/10 border-2 border-red-200 dark:border-red-900/50 rounded-2xl overflow-hidden">
          <button 
             onClick={() => setShowContraindicated(!showContraindicated)}
             className="w-full flex items-center justify-between p-4 bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-200 font-bold"
          >
             <div className="flex items-center gap-2">
                <Octagon size={20} /> Strictly Contraindicated Drugs (Always Unsafe)
             </div>
             {showContraindicated ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
          </button>

          {showContraindicated && (
             <div className="p-4 grid gap-3 md:grid-cols-2 animate-fade-in">
                {ALWAYS_CONTRAINDICATED.map((drug, i) => (
                   <div key={i} className="bg-white dark:bg-deep-card p-3 rounded-xl border border-red-100 dark:border-red-900/30">
                      <p className="font-bold text-red-700 dark:text-red-400">{drug.name}</p>
                      <p className="text-xs text-gray-600 dark:text-gray-300 mt-1">{drug.reason}</p>
                   </div>
                ))}
             </div>
          )}
       </div>

      {/* Guide Section */}
      <div className="space-y-4">
        <div className="flex items-center justify-between mb-2 px-2">
          <h3 className="text-xl font-bold text-gray-800 dark:text-white">
             {trimesterTitle} Medicines Guide
          </h3>
          <span className="text-xs font-medium text-gray-500 bg-gray-100 dark:bg-indigo-900/50 px-3 py-1 rounded-full">
            {isPostpartum ? 'Safe for Baby' : (mode === 'planning' ? 'Conception Safe' : `Week ${currentWeek}`)}
          </span>
        </div>

        {guideData?.map((category, idx) => (
          <div key={idx} className="bg-white dark:bg-deep-card rounded-2xl shadow-sm border border-gray-100 dark:border-indigo-800 overflow-hidden">
            <button 
              onClick={() => toggleCategory(idx)}
              className="w-full flex items-center justify-between p-5 text-left hover:bg-gray-50 dark:hover:bg-white/5 transition-colors"
            >
              <h4 className="font-bold text-lg text-gray-800 dark:text-white flex items-center gap-2">
                {category.category}
              </h4>
              {expandedCategory === idx ? <ChevronUp size={20} className="text-gray-400" /> : <ChevronDown size={20} className="text-gray-400" />}
            </button>

            {expandedCategory === idx && (
              <div className="p-5 pt-0 border-t border-gray-100 dark:border-indigo-800/50 animate-fade-in">
                <div className="mt-4 grid gap-4 md:grid-cols-2">
                  {/* Safe Column */}
                  <div className="bg-green-50 dark:bg-green-900/10 p-4 rounded-xl border border-green-100 dark:border-green-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-green-700 dark:text-green-400 mb-2 text-sm uppercase tracking-wide">
                        <ShieldCheck size={16} /> Safe
                     </h5>
                     <ul className="space-y-1">
                        {category.safe.map((m, i) => (
                           <li key={i} className="text-sm text-gray-700 dark:text-gray-300">• {m}</li>
                        ))}
                     </ul>
                  </div>

                  {/* Avoid Column */}
                  <div className="bg-red-50 dark:bg-red-900/10 p-4 rounded-xl border border-red-100 dark:border-red-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-red-700 dark:text-red-400 mb-2 text-sm uppercase tracking-wide">
                        <XCircle size={16} /> Avoid
                     </h5>
                     <ul className="space-y-1">
                        {category.avoid.map((m, i) => (
                           <li key={i} className="text-sm text-gray-700 dark:text-gray-300">• {m}</li>
                        ))}
                     </ul>
                  </div>
                </div>

                {/* Caution */}
                {category.caution.length > 0 && (
                  <div className="mt-4 bg-yellow-50 dark:bg-yellow-900/10 p-4 rounded-xl border border-yellow-100 dark:border-yellow-900/30">
                     <h5 className="flex items-center gap-2 font-bold text-yellow-700 dark:text-yellow-400 mb-2 text-sm uppercase tracking-wide">
                        <AlertTriangle size={16} /> Use with Caution
                     </h5>
                     <p className="text-sm text-gray-700 dark:text-gray-300">
                        {category.caution.join(', ')}
                     </p>
                  </div>
                )}

                {/* Note */}
                {category.note && (
                   <div className="mt-4 text-sm italic text-gray-500 dark:text-gray-400 border-l-4 border-bloom-DEFAULT pl-3">
                      Note: {category.note}
                   </div>
                )}
              </div>
            )}
          </div>
        ))}

        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-sm text-blue-800 dark:text-blue-200 border border-blue-100 dark:border-blue-900/30 flex items-start gap-3">
             <Info className="shrink-0 mt-0.5" size={18} />
             <p>This list assumes a low-risk {isPostpartum ? 'recovery' : 'pregnancy'}. If you have underlying conditions (Diabetes, Hypertension, etc.), always consult your doctor before taking "Safe" medications. Data based on FOGSI & Indian Formulary.</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserSettings, PregnancyCalculations, TabView, ProfileMeta, Medicine } from './types';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { PostpartumDashboard } from './components/PostpartumDashboard';
import { PrePregnancyDashboard } from './components/PrePregnancyDashboard';
import { Timeline } from './components/Timeline';
import { ReportAnalyzer } from './components/ReportAnalyzer';
import { MedicineTracker } from './components/MedicineTracker';
import { Profile } from './components/Profile';
import { DietPlan } from './components/DietPlan';
import { VaccinationTracker } from './components/VaccinationTracker';
import { ToolsHub } from './components/ToolsHub';
import { HealthTracker } from './components/HealthTracker';
import { Login } from './components/Login';
import { LayoutDashboard, Calendar, FileText, Pill, Moon, Sun, Settings, User, Utensils, Syringe, Baby, Wrench, HeartPulse, LogOut, Users, PlusCircle } from 'lucide-react';

// Keys that store profile-specific data which need to be swapped on profile switch
const PROFILE_SPECIFIC_KEYS = [
  'bloom_kicks',
  'bloom_contractions',
  'bloom_milestones',
  'bloom_weight_logs',
  'bloom_pp_weight_logs',
  'bloom_bp_logs',
  'bloom_pp_bp_logs',
  'bloom_glucose_logs',
  'bloom_pp_glucose_logs',
  'bloom_baby_growth',
  'bloom_tsh_logs', 'bloom_pp_tsh_logs',
  'bloom_hb_logs', 'bloom_pp_hb_logs',
  'bloom_hba1c_logs', 'bloom_pp_hba1c_logs',
  'bloom_medicines', 'bloom_pp_medicines' // Added Medicine Keys
];

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [activeTab, setActiveTab] = useState<TabView>(TabView.DASHBOARD);

  // Profile Management State
  const [profiles, setProfiles] = useState<ProfileMeta[]>([]);
  const [showProfileSwitcher, setShowProfileSwitcher] = useState(false);

  // Load auth & settings & profile meta
  useEffect(() => {
    const auth = localStorage.getItem('bloom_auth');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }

    const savedSettings = localStorage.getItem('bloom_settings');
    const savedProfiles = localStorage.getItem('bloom_all_profiles');

    if (savedSettings) {
      const parsed = JSON.parse(savedSettings);

      // Legacy Migration: If no ID, assign one and create profile meta
      if (!parsed.id) {
          parsed.id = 'default_profile_' + Date.now();
          localStorage.setItem('bloom_settings', JSON.stringify(parsed));
      }

      // Default field migrations for older data
      if (!parsed.status) parsed.status = parsed.isPostpartum ? 'postpartum' : 'pregnant';
      if (!parsed.comorbidities) parsed.comorbidities = [];
      if (!parsed.dietaryPreference) parsed.dietaryPreference = 'vegetarian';
      if (parsed.lactoseIntolerant === undefined) parsed.lactoseIntolerant = false;
      if (!parsed.vaccinationsDone) parsed.vaccinationsDone = [];
      if (!parsed.preConceptionChecklist) parsed.preConceptionChecklist = [];
      if (!parsed.periodLog) parsed.periodLog = [];
      if (parsed.pregnancyLmp === undefined) parsed.pregnancyLmp = null;
      if (!parsed.maternalBloodGroup) parsed.maternalBloodGroup = '';

      // Migration for new Risk Features (Obstetric History & Age)
      if (!parsed.obstetricHistory) {
          parsed.obstetricHistory = {
              gravida: 1,
              para: 0,
              abortions: 0,
              abortionsT1: 0,
              abortionsT2: 0,
              living: 0,
              lastBabyCongenitalDefect: false
          };
      }
      if (parsed.age === undefined) parsed.age = 0; 

      setSettings(parsed);

      // Initialize Profiles List
      if (savedProfiles) {
          setProfiles(JSON.parse(savedProfiles));
      } else {
          // Create initial profile list from current settings
          const initialProfile: ProfileMeta = {
              id: parsed.id,
              name: parsed.name,
              status: parsed.status,
              babyName: parsed.babyName,
              babyGender: parsed.babyGender,
              birthDate: parsed.birthDate,
              lastActive: new Date().toISOString()
          };
          setProfiles([initialProfile]);
          localStorage.setItem('bloom_all_profiles', JSON.stringify([initialProfile]));
      }
    }
  }, []);

  // Request Notification Permission on Mount
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  // Global Medicine Notification Checker
  useEffect(() => {
    if (!settings) return;

    const checkMedicines = () => {
      if ('Notification' in window && Notification.permission === 'granted') {
        const isPostpartum = settings.status === 'postpartum';
        const key = isPostpartum ? 'bloom_pp_medicines' : 'bloom_medicines';
        const stored = localStorage.getItem(key);

        if (stored) {
          const medicines: Medicine[] = JSON.parse(stored);
          const now = new Date();
          const currentHours = now.getHours();
          const currentMinutes = now.getMinutes();

          medicines.forEach(med => {
            if (!med.taken && med.time) {
              const [medHours, medMinutes] = med.time.split(':').map(Number);
              // Trigger if times match exactly
              if (medHours === currentHours && medMinutes === currentMinutes) {
                new Notification('Bloom: Medicine Reminder', {
                  body: `It's time to take your ${med.name} (${med.dosage})`,
                  icon: '/icon-192x192.png' // Assumes standard PWA icon path or fallback
                });
              }
            }
          });
        }
      }
    };

    // Check every minute
    const interval = setInterval(checkMedicines, 60000);
    return () => clearInterval(interval);
  }, [settings]);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Profile Switching Logic ---

  const handleSwitchProfile = (targetProfileId: string) => {
      if (!settings || settings.id === targetProfileId) return;

      // 1. Snapshot Current Profile Data
      // Save current active logs into namespaced keys (e.g. bloom_kicks_profile_1)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) {
              localStorage.setItem(`${key}_${settings.id}`, data);
          } else {
              localStorage.removeItem(`${key}_${settings.id}`);
          }
      });
      // Save current settings to namespaced key
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Hydrate Target Profile Data
      // Load target profile logs into active keys
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const savedData = localStorage.getItem(`${key}_${targetProfileId}`);
          if (savedData) {
              localStorage.setItem(key, savedData);
          } else {
              localStorage.removeItem(key); // Clear if no data for target
          }
      });

      // 3. Load Target Settings
      const targetSettingsRaw = localStorage.getItem(`bloom_settings_${targetProfileId}`);
      if (targetSettingsRaw) {
          const targetSettings = JSON.parse(targetSettingsRaw);
          setSettings(targetSettings);
          localStorage.setItem('bloom_settings', targetSettingsRaw); // Set as active settings

          // Update Meta Last Active
          const updatedProfiles = profiles.map(p => 
              p.id === targetProfileId ? { ...p, lastActive: new Date().toISOString() } : p
          );
          setProfiles(updatedProfiles);
          localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

          // Refresh to ensure all sub-components read new localStorage values
          window.location.reload(); 
      }
  };

  const handleAddProfile = () => {
      if (!settings) return;

      // 1. Snapshot Current Data (Same as switch)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) localStorage.setItem(`${key}_${settings.id}`, data);
          else localStorage.removeItem(`${key}_${settings.id}`);
      });
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Create New Settings (Inherit Shared Data)
      const newId = `profile_${Date.now()}`;
      const newSettings: UserSettings = {
          id: newId,
          name: settings.name, // Mom's name is shared
          status: 'planning', // Default to planning for new journey
          lmp: null,
          cycleLength: settings.cycleLength,

          // Shared Stats (Don't make mom re-enter)
          heightCm: settings.heightCm,
          prePregnancyWeight: settings.prePregnancyWeight, // Might change, but good default
          maternalBloodGroup: settings.maternalBloodGroup,
          paternalBloodGroup: settings.paternalBloodGroup,
          paternalHeightCm: settings.paternalHeightCm,
          obstetricHistory: settings.obstetricHistory, // Copy history
          comorbidities: settings.comorbidities, // Usually persistent
          dietaryPreference: settings.dietaryPreference,
          lactoseIntolerant: settings.lactoseIntolerant,
          age: settings.age,

          // Reset Logs for new baby
          periodLog: [],
          vaccinationsDone: [],
          isPostpartum: false,
          preConceptionChecklist: []
      };

      // 3. Clear Active Keys for fresh start
      PROFILE_SPECIFIC_KEYS.forEach(key => localStorage.removeItem(key));

      // 4. Update State & Storage
      setSettings(newSettings);
      localStorage.setItem('bloom_settings', JSON.stringify(newSettings));

      const newProfileMeta: ProfileMeta = {
          id: newId,
          name: newSettings.name,
          status: 'planning',
          babyName: undefined,
          lastActive: new Date().toISOString()
      };

      const updatedProfiles = [...profiles, newProfileMeta];
      setProfiles(updatedProfiles);
      localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

      // Force reload to apply clean state
      window.location.reload();
  };

  const calculations: PregnancyCalculations | null = useMemo(() => {
    if (!settings || !settings.lmp) return null;

    const lmpDate = new Date(settings.lmp);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - lmpDate.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    // Logic: Naegele's rule adjusted
    const cycleAdjustment = settings.cycleLength - 28;
    const edd = new Date(lmpDate);
    edd.setDate(edd.getDate() + 280 + cycleAdjustment);

    const weeks = Math.floor(diffDays / 7);
    const days = diffDays % 7;

    let trimester: 1 | 2 | 3 = 1;
    if (weeks > 13) trimester = 2;
    if (weeks > 27) trimester = 3;

    return {
      edd,
      currentWeek: weeks === 0 ? 1 : weeks, // Minimum week 1
      currentDay: days,
      totalDays: diffDays,
      trimester,
      month: Math.ceil(weeks / 4.3),
      progressPercent: Math.min((diffDays / 280) * 100, 100)
    };
  }, [settings]);

  // Determine App Mode based on Settings Status
  const isPostpartum = settings?.status === 'postpartum';
  const isPlanning = settings?.status === 'planning';
  const isPregnant = settings?.status === 'pregnant';

  // Dynamic Theme Logic (Strict Gender Colors for Postpartum)
  let themeColor = 'text-pink-600';
  let activeBg = 'bg-pink-600 text-white shadow-pink-500/30';
  let bgGradient = 'bg-gradient-to-r from-pink-600 to-purple-600';
  let badgeColor = 'bg-pink-100 text-pink-600';

  if (isPlanning) {
      themeColor = 'text-teal-600';
      activeBg = 'bg-teal-600 text-white shadow-teal-500/30';
      bgGradient = 'bg-gradient-to-r from-teal-500 to-emerald-600';
      badgeColor = 'bg-teal-100 text-teal-600';
  } else if (isPostpartum) {
      if (settings?.babyGender === 'boy') {
          themeColor = 'text-blue-600';
          activeBg = 'bg-blue-600 text-white shadow-blue-500/30';
          bgGradient = 'bg-gradient-to-r from-blue-600 to-cyan-600';
          badgeColor = 'bg-blue-100 text-blue-600';
      } else {
          // Explicit Pink for Girl (Postpartum) to differ from Pregnancy Purple/Pink mix
          themeColor = 'text-rose-500';
          activeBg = 'bg-rose-500 text-white shadow-rose-500/30';
          bgGradient = 'bg-gradient-to-r from-rose-400 to-pink-500';
          badgeColor = 'bg-rose-100 text-rose-600';
      }
  }

  const getBabyAgeInWeeks = () => {
    if (!settings?.birthDate) return 0;
    const birth = new Date(settings.birthDate);
    const now = new Date();
    const diff = Math.abs(now.getTime() - birth.getTime());
    return Math.floor(diff / (1000 * 60 * 60 * 24 * 7));
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem('bloom_auth', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('bloom_auth');
    setActiveTab(TabView.DASHBOARD);
  };

  const handleOnboardingComplete = (data: UserSettings) => {
    // Inject ID if missing from Onboarding
    if (!data.id) data.id = 'profile_' + Date.now();

    // Initial sync of log if date provided
    if (data.lmp) {
        data.periodLog = [data.lmp];
        data.pregnancyLmp = data.status === 'pregnant' ? data.lmp : null;
    }

    // Ensure new fields are initialized
    if (!data.obstetricHistory) {
        data.obstetricHistory = {
            gravida: 1,
            para: 0,
            abortions: 0,
            abortionsT1: 0,
            abortionsT2: 0,
            living: 0,
            lastBabyCongenitalDefect: false
        };
    }
    if (data.age === undefined) data.age = 0;

    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Initialize Profiles List for new user
    const meta: ProfileMeta = {
        id: data.id,
        name: data.name,
        status: data.status,
        babyName: data.babyName,
        babyGender: data.babyGender,
        birthDate: data.birthDate,
        lastActive: new Date().toISOString()
    };
    setProfiles([meta]);
    localStorage.setItem('bloom_all_profiles', JSON.stringify([meta]));
  };

  const handleUpdateProfile = (data: UserSettings) => {
    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Update Meta in Profile List
    const updatedProfiles = profiles.map(p => 
        p.id === data.id ? { 
            ...p, 
            name: data.name, 
            status: data.status, 
            babyName: data.babyName,
            babyGender: data.babyGender,
            birthDate: data.birthDate
        } : p
    );
    setProfiles(updatedProfiles);
    localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));
  };

  const handleVaccineUpdate = (vaxId: string) => {
    if (!settings) return;
    const currentDone = settings.vaccinationsDone || [];
    let newDone;
    if (currentDone.includes(vaxId)) {
        newDone = currentDone.filter(id => id !== vaxId);
    } else {
        newDone = [...currentDone, vaxId];
    }
    const newSettings = { ...settings, vaccinationsDone: newDone };
    setSettings(newSettings);
    localStorage.setItem('bloom_settings', JSON.stringify(newSettings));
  };

  const handleReset = () => {
    localStorage.clear();
    setTimeout(() => {
        window.location.reload();
    }, 50);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (!settings) {
    return (
      <>
        <div className="fixed top-4 right-4 z-50">
           <button onClick={() => setDarkMode(!darkMode)} className="p-3 rounded-full bg-white dark:bg-deep-card shadow-lg text-bloom-DEFAULT dark:text-yellow-400">
