          <div className="space-y-4">
              <div className="flex flex-col md:flex-row gap-4">
                  <div className="relative flex-1">
                      <input 
                          type="text" 
                          placeholder="Search 500+ Indian foods (e.g. 'Ragi', 'Dal', 'Paneer')..." 
                          className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-pink-500"
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                      />
                      <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                  </div>

                  {/* Filter Toggle */}
                  <div 
                    onClick={() => setShowCompatibleOnly(!showCompatibleOnly)}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer select-none transition-all ${showCompatibleOnly ? 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-800' : 'bg-gray-50 border-gray-200 dark:bg-gray-800 dark:border-gray-700'}`}
                  >
                      <div className={`w-10 h-6 rounded-full relative transition-colors ${showCompatibleOnly ? 'bg-green-500' : 'bg-gray-400'}`}>
                          <div className={`w-4 h-4 bg-white rounded-full absolute top-1 transition-all ${showCompatibleOnly ? 'left-5' : 'left-1'}`}></div>
                      </div>
                      <span className="text-xs font-bold text-gray-700 dark:text-gray-300">
                          {showCompatibleOnly ? 'Showing Suitable Only' : 'Showing All Foods'}
                      </span>
                  </div>
              </div>

              <div className="grid gap-3">
                  {filteredLibrary.length > 0 ? (
                      filteredLibrary.slice(0, 50).map((item) => {
                          const { suitable, issues } = checkSuitability(item);
                          const tags = getTagsForFood(item);

                          // Opacity for unsuitable items
                          const opacityClass = suitable ? 'opacity-100' : 'opacity-60 grayscale-[0.5]';

                          return (
                              <div key={item.id} className={`bg-white dark:bg-deep-card p-4 rounded-xl border hover:shadow-md transition-all flex flex-col md:flex-row md:items-center justify-between gap-4 ${opacityClass} ${suitable ? 'border-gray-100 dark:border-indigo-800' : 'border-red-100 dark:border-red-900/30'}`}>
                                  <div className="flex-1">
                                      <div className="flex items-center gap-2 flex-wrap">
                                          <h4 className="font-bold text-gray-800 dark:text-white">{item.name}</h4>
                                          <span className="text-[10px] uppercase font-bold text-gray-400 bg-gray-100 dark:bg-gray-800 px-2 py-0.5 rounded">{item.category}</span>
                                          {!suitable && (
                                              <span className="flex items-center gap-1 text-[10px] font-bold text-red-600 bg-red-100 dark:bg-red-900/50 px-2 py-0.5 rounded border border-red-200 dark:border-red-800">
                                                  <XCircle size={10} /> Avoid: {issues.join(', ')}
                                              </span>
                                          )}
                                      </div>
                                      <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{item.desc}</p>
                                      <div className="flex flex-wrap gap-2 mt-2">
                                          {tags.map((t, i) => (
                                              <span key={i} className={`text-[10px] font-bold px-2 py-0.5 rounded-full border border-transparent ${t.color}`}>
                                                  {t.text}
                                              </span>
                                          ))}
                                      </div>
                                  </div>
                                  <div className="flex gap-2 shrink-0">
                                      {(item.category === 'Veg' || item.category === 'Fruit' || item.category === 'Cereals' || item.category === 'Pulses') && <div className="w-3 h-3 rounded-full border-2 border-green-600 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-green-600 rounded-full"></div></div>}
                                      {item.category === 'NonVeg' && <div className="w-3 h-3 rounded-full border-2 border-red-600 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-red-600 rounded-full"></div></div>}
                                      {(item.category === 'Dairy' || item.category === 'Bev') && <div className="w-3 h-3 rounded-full border-2 border-yellow-500 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-yellow-500 rounded-full"></div></div>}
                                  </div>
                              </div>
                          );
                      })
                  ) : (
                      <div className="text-center py-10 text-gray-400">
                          <p>No foods found matching "{searchTerm}" {showCompatibleOnly ? 'in your suitable list' : ''}.</p>
                          <p className="text-xs mt-1">Try turning off the "Suitable Only" filter to see all items.</p>
                      </div>
                  )}
                  {filteredLibrary.length > 50 && (
                      <p className="text-center text-xs text-gray-400 mt-2">Showing top 50 of {filteredLibrary.length} matches.</p>
                  )}
              </div>
          </div>
      )}

      {/* --- TAB: GUIDE --- */}
      {activeTab === 'guide' && (
          <div className="space-y-6">
              <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30">
                  <h3 className="font-bold text-blue-800 dark:text-blue-300 mb-4 flex items-center gap-2">
                      <Star size={20} /> Nutritional Guidelines (ICMR-NIN India)
                  </h3>
                  <div className="space-y-4 text-sm text-blue-900 dark:text-blue-200">
                      <div>
                          <strong className="block mb-1">Calorie Intake:</strong>
                          <p>Pregnancy requires only +350 kcal in T2 and +450 kcal in T3. Lactation requires +600 kcal. Do not "eat for two" in volume, but in quality.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Protein:</strong>
                          <p>Aim for 60-70g daily. Essential for baby's tissue growth. Include Dal/Paneer/Egg in every meal.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Iron & Folic Acid:</strong>
                          <p>Crucial to prevent anemia. Pair Iron foods (Dates, Spinach) with Vitamin C (Lemon) for absorption. Avoid Tea/Coffee 1 hour before/after meals.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Calcium:</strong>
                          <p>1200mg/day. Milk, Curd, Ragi, Sesame seeds. Do not take Iron and Calcium supplements together (they block each other).</p>
                      </div>
                  </div>
              </div>

              {comorbidities.length > 0 && (
                  <div className="bg-red-50 dark:bg-red-900/10 p-6 rounded-3xl border border-red-100 dark:border-red-900/30">
                      <h3 className="font-bold text-red-800 dark:text-red-300 mb-4 flex items-center gap-2">
                          <AlertTriangle size={20} /> Comorbidity Alerts
                      </h3>
                      <ul className="space-y-3">
                          {comorbidities.map(c => {
                              const logic = DIET_LOGIC.comorbidities[c as keyof typeof DIET_LOGIC.comorbidities];
                              if(!logic) return null;
                              return (
                                  <li key={c}>
                                      <strong className="text-red-700 dark:text-red-400 block">{logic.name}</strong>
                                      <p className="text-xs text-red-600 dark:text-red-300 mt-1">
                                          Avoid: {logic.avoid.join(', ').replace(/_/g, ' ')}. <br/>
                                          Prioritize: {logic.prioritize.join(', ').replace(/_/g, ' ')}.
                                      </p>
                                  </li>
                              );
                          })}
                      </ul>
                  </div>
              )}
          </div>
      )}

    </div>
  );
};

