        t3: { focus: "Energy & Acid-Reflux", prioritize: ['t3_energy', 'energy', 'acid_safe', 'small_meals'], note: "Light dinners to avoid heartburn." },
        postpartum: { focus: "Lactation & Healing", prioritize: ['postpartum_healing', 'lactation', 'calcium', 'hydration'], note: "Galactogogues for milk supply." }
    }
};

// Removed static MEAL_PLAN_TEMPLATES as they are replaced by dynamic logic in DietPlan.tsx
export const MEAL_PLAN_TEMPLATES = {};

import React, { useState, useMemo, useEffect } from 'react';
import { UserSettings, PregnancyCalculations, DietType } from '../types';
import { FOOD_LIBRARY, DIET_LOGIC, DIET_PATTERNS } from '../constants';
import { Coffee, Utensils, Moon, Sun, Apple, Info, AlertTriangle, Droplet, Search, Filter, CheckCircle2, ChevronRight, Star, Baby, Heart, ChevronDown, XCircle, RefreshCw } from 'lucide-react';

interface Props {
  settings: UserSettings;
  calculations: PregnancyCalculations;
}

export const DietPlan: React.FC<Props> = ({ settings, calculations }) => {
  const [activeTab, setActiveTab] = useState<'plan' | 'library' | 'guide'>('plan');
  const [searchTerm, setSearchTerm] = useState('');

  // -- CONTEXT DERIVATION --
  const isPostpartum = settings.isPostpartum;
  const trimester = calculations.trimester;
  const dietType = settings.dietaryPreference || 'vegetarian';
  const comorbidities = settings.comorbidities || [];

  // -- BMI Logic --
  const getBmiCategory = () => {
      if(!settings.prePregnancyWeight || !settings.heightCm) return 'normal';
      const bmi = settings.prePregnancyWeight / ((settings.heightCm/100)**2);
      if(bmi < 18.5) return 'underweight';
      if(bmi >= 30) return 'obese';
      if(bmi >= 25) return 'overweight';
      return 'normal';
  };
  const bmiCat = getBmiCategory();
  const bmiInfo = DIET_LOGIC.bmi[bmiCat];

  // -- STAGE SELECTION STATE --
  const getDefaultStage = () => {
      if (settings.status === 'planning') return 'planning';
      if (settings.status === 'postpartum') return 'postpartum';
      return trimester === 1 ? 't1' : trimester === 2 ? 't2' : 't3';
  };

  const [selectedStage, setSelectedStage] = useState<string>(getDefaultStage());

  useEffect(() => {
      setSelectedStage(getDefaultStage());
  }, [settings.status, trimester]);

  // @ts-ignore
  const stageInfo = DIET_LOGIC.stages[selectedStage] || DIET_LOGIC.stages.t1;

  // -- LIBRARY FILTER STATE --
  const [showCompatibleOnly, setShowCompatibleOnly] = useState(true);

  // -- SUITABILITY CHECKER --
  const checkSuitability = (item: any) => {
      const issues: string[] = [];

      // 1. Diet Type Check
      if (dietType === 'vegetarian' && item.category === 'NonVeg') issues.push('Non-Veg');
      if (dietType === 'eggetarian' && item.category === 'NonVeg' && !item.name.includes('Egg')) issues.push('Non-Veg (Meat)');

      // 2. Lactose Intolerance
      if (settings.lactoseIntolerant && item.category === 'Dairy' && !item.name.includes('Curd') && !item.name.includes('Ghee')) issues.push('Lactose');

      // 3. Comorbidities
      for (const condition of comorbidities) {
          const logic = DIET_LOGIC.comorbidities[condition as keyof typeof DIET_LOGIC.comorbidities];
          if (logic && logic.avoid) {
              if (item.tags.some((t: string) => logic.avoid.includes(t))) {
                  issues.push(logic.name); // e.g., "Diabetes", "Hypertension"
              }
          }
      }

      return { suitable: issues.length === 0, issues };
  };

  // -- SMART MEAL GENERATOR (SCORING SYSTEM) --
  const getSmartSuggestion = (category: string) => {
      // 1. Filter Library by Category
      let candidates = FOOD_LIBRARY.filter(f => f.category === category);

      // 2. Strict Filters (Diet/Allergies/Comorbidities)
      candidates = candidates.filter(f => checkSuitability(f).suitable);

      // 3. Scoring System
      const scoredCandidates = candidates.map(item => {
          let score = 0;

          // Stage Priority
          if(stageInfo.prioritize.some((t: string) => item.tags.includes(t))) score += 5;

          // Comorbidity Priority
          comorbidities.forEach(c => {
              const cLogic = DIET_LOGIC.comorbidities[c as keyof typeof DIET_LOGIC.comorbidities];
              if(cLogic && cLogic.prioritize.some((t: string) => item.tags.includes(t))) score += 10;
          });

          // Nutrient density fallback
          if(item.tags.includes('protein')) score += 2;
          if(item.tags.includes('iron')) score += 2;
          if(item.tags.includes('calcium')) score += 2;

          return { item, score };
      });

      // 4. Sort and Pick Top
      scoredCandidates.sort((a, b) => b.score - a.score);

      // Return top 2 unique items
      return scoredCandidates.slice(0, 2).map(s => s.item);
  };

  const getTagsForFood = (item: any) => {
      let displayTags = [];
      if(item.tags.includes('protein')) displayTags.push({text: 'Protein', color: 'bg-blue-100 text-blue-700'});
      if(item.tags.includes('iron')) displayTags.push({text: 'Iron', color: 'bg-red-100 text-red-700'});
      if(item.tags.includes('calcium')) displayTags.push({text: 'Calcium', color: 'bg-gray-100 text-gray-700'});
      if(item.tags.includes('gdm_safe')) displayTags.push({text: 'Low GI', color: 'bg-emerald-100 text-emerald-700'});
      if(item.tags.includes('lactation')) displayTags.push({text: 'Milk Boost', color: 'bg-purple-100 text-purple-700'});
      return displayTags;
  };

  // -- LIBRARY FILTER --
  const filteredLibrary = useMemo(() => {
      return FOOD_LIBRARY.filter(item => {
          const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                                item.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
                                item.tags.some(t => t.includes(searchTerm.toLowerCase()));

          if (!matchesSearch) return false;

          if (showCompatibleOnly) {
              const { suitable } = checkSuitability(item);
              if (!suitable) return false;
          }

          return true;
      });
  }, [searchTerm, settings, comorbidities, showCompatibleOnly, dietType]);

  const stagesOptions = [
      { value: 'planning', label: 'Planning / Fertility' },
      { value: 't1', label: 'Trimester 1 (Week 1-13)' },
      { value: 't2', label: 'Trimester 2 (Week 14-27)' },
      { value: 't3', label: 'Trimester 3 (Week 28-40)' },
      { value: 'postpartum', label: 'Postpartum / Lactation' }
  ];

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-10">

      {/* Header Profile Summary */}
      <div className={`rounded-3xl p-6 text-white shadow-lg bg-gradient-to-r ${settings.status === 'planning' ? 'from-teal-500 to-emerald-600' : isPostpartum ? 'from-purple-600 to-indigo-600' : 'from-pink-600 to-rose-500'}`}>
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                  <h2 className="text-2xl font-bold flex items-center gap-2">
                      {settings.status === 'planning' ? <Heart /> : isPostpartum ? <Baby /> : <Apple />} 
                      Diet & Nutrition
                  </h2>
                  <div className="flex flex-wrap gap-2 mt-2 text-xs font-bold uppercase tracking-wide opacity-90">
                      <span className="bg-white/20 px-2 py-1 rounded">{dietType}</span>
                      <span className="bg-white/20 px-2 py-1 rounded">{bmiInfo.label} BMI</span>
                      {comorbidities.map(c => (
                          <span key={c} className="bg-red-500/40 px-2 py-1 rounded border border-white/20">{DIET_LOGIC.comorbidities[c as keyof typeof DIET_LOGIC.comorbidities]?.name}</span>
                      ))}
                  </div>
              </div>
              <div className="text-right">
                  <p className="text-sm font-medium opacity-80 mb-1">Current Focus</p>
                  <p className="text-lg font-bold bg-white/20 px-3 py-1 rounded-lg backdrop-blur-sm inline-block">{stageInfo.focus}</p>
              </div>
          </div>

          <div className="mt-6 bg-white/10 p-4 rounded-xl backdrop-blur-sm border border-white/10">
              <div className="flex items-start gap-3">
                  <Info className="shrink-0 mt-1" size={18} />
                  <p className="text-sm leading-relaxed">{bmiInfo.advice} {stageInfo.note}</p>
              </div>
          </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 bg-gray-100 dark:bg-indigo-900/30 p-1 rounded-xl overflow-x-auto">
          {['plan', 'library', 'guide'].map((tab) => (
              <button
                  key={tab}
                  onClick={() => setActiveTab(tab as any)}
                  className={`flex-1 px-4 py-2 rounded-lg text-sm font-bold capitalize transition-all whitespace-nowrap ${activeTab === tab ? 'bg-white dark:bg-deep-card shadow text-pink-600' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
              >
                  {tab === 'plan' ? 'Daily Menu' : tab === 'library' ? 'Food Library (100+)' : 'Nutrition Guide'}
              </button>
          ))}
      </div>

      {/* --- TAB: MEAL PLAN (DYNAMIC) --- */}
      {activeTab === 'plan' && (
          <div className="space-y-6">
              {/* Stage Filter for Plan */}
              <div className="flex justify-end">
                  <div className="relative inline-block w-full md:w-64">
                      <select
                          value={selectedStage}
                          onChange={(e) => setSelectedStage(e.target.value)}
                          className="w-full appearance-none bg-white dark:bg-deep-card border border-gray-200 dark:border-indigo-800 text-gray-700 dark:text-gray-200 py-2 px-4 pr-8 rounded-xl font-medium focus:outline-none focus:ring-2 focus:ring-pink-500 cursor-pointer"
                      >
                          {stagesOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                      </select>
                      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" size={16} />
                  </div>
              </div>

              {Object.entries(DIET_PATTERNS).map(([key, section]) => {
                  let Icon = Sun;
                  if(key.includes('lunch')) Icon = Utensils;
                  if(key.includes('dinner')) Icon = Moon;
                  if(key.includes('snack')) Icon = Coffee;

                  return (
                      <div key={key} className="bg-white dark:bg-deep-card rounded-2xl shadow-sm border border-gray-100 dark:border-indigo-800 overflow-hidden">
                          <div className="bg-gray-50 dark:bg-indigo-900/30 p-4 flex items-center justify-between border-b border-gray-100 dark:border-indigo-800">
                              <div className="flex items-center gap-3">
                                  <div className="p-2 bg-white dark:bg-deep-card rounded-full shadow-sm text-pink-500">
                                      <Icon size={18} />
                                  </div>
                                  <h3 className="font-bold text-gray-800 dark:text-white">{section.title}</h3>
                              </div>
                          </div>

                          <div className="p-4 space-y-4">
                              {section.components.map((comp, idx) => {
                                  const suggestions = getSmartSuggestion(comp.type);

                                  const displayText = suggestions.length > 0 
                                      ? suggestions.map(s => s.name).join(' / ')
                                      : `Any safe ${comp.role}`;

                                  return (
                                      <div key={idx} className="flex flex-col md:flex-row md:items-center gap-2">
                                          <div className="min-w-[140px] text-xs font-bold uppercase text-gray-500 dark:text-gray-400 flex items-center gap-2">
                                              <span className="w-1.5 h-1.5 rounded-full bg-pink-400"></span>
                                              {comp.role}
                                          </div>
                                          <div className="flex-1 p-3 bg-pink-50/50 dark:bg-indigo-900/10 rounded-xl border border-pink-100 dark:border-indigo-800 text-sm font-medium text-gray-800 dark:text-gray-200">
                                              {displayText}
                                          </div>
                                      </div>
                                  );
                              })}

                              {/* Dynamic BMI/Comorbidity Instruction Injection */}
                              <div className="flex flex-wrap gap-2 mt-2">
                                  <span className="text-[10px] bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 px-2 py-1 rounded border border-gray-200 dark:border-gray-700 flex items-center gap-1">
                                      <Info size={10} /> Tip: {bmiInfo.instruction}
                                  </span>
                                  {comorbidities.map(c => {
                                      const inst = DIET_LOGIC.comorbidities[c as keyof typeof DIET_LOGIC.comorbidities]?.instruction;
                                      if(inst) return (
                                          <span key={c} className="text-[10px] bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 px-2 py-1 rounded border border-red-100 dark:border-red-900/30">
                                              {inst}
                                          </span>
                                      );
                                      return null;
                                  })}
                              </div>
                          </div>
                      </div>
                  );
              })}
          </div>
      )}

      {/* --- TAB: FOOD LIBRARY --- */}
      {activeTab === 'library' && (
          <div className="space-y-4">
              <div className="flex flex-col md:flex-row gap-4">
                  <div className="relative flex-1">
                      <input 
                          type="text" 
                          placeholder="Search 100+ foods (e.g. 'Ragi', 'Dal', 'Paneer')..." 
                          className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-pink-500"
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                      />
                      <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                  </div>

                  {/* Filter Toggle */}
                  <div 
                    onClick={() => setShowCompatibleOnly(!showCompatibleOnly)}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer select-none transition-all ${showCompatibleOnly ? 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-800' : 'bg-gray-50 border-gray-200 dark:bg-gray-800 dark:border-gray-700'}`}
                  >
                      <div className={`w-10 h-6 rounded-full relative transition-colors ${showCompatibleOnly ? 'bg-green-500' : 'bg-gray-400'}`}>
                          <div className={`w-4 h-4 bg-white rounded-full absolute top-1 transition-all ${showCompatibleOnly ? 'left-5' : 'left-1'}`}></div>
                      </div>
                      <span className="text-xs font-bold text-gray-700 dark:text-gray-300">
                          {showCompatibleOnly ? 'Suitable Only' : 'Show All'}
                      </span>
                  </div>
              </div>

              <div className="grid gap-3">
                  {filteredLibrary.length > 0 ? (
                      filteredLibrary.slice(0, 100).map((item) => {
                          const { suitable, issues } = checkSuitability(item);
                          const tags = getTagsForFood(item);

                          // Opacity for unsuitable items
                          const opacityClass = suitable ? 'opacity-100' : 'opacity-60 grayscale-[0.5]';

                          return (
                              <div key={item.id} className={`bg-white dark:bg-deep-card p-4 rounded-xl border hover:shadow-md transition-all flex flex-col md:flex-row md:items-center justify-between gap-4 ${opacityClass} ${suitable ? 'border-gray-100 dark:border-indigo-800' : 'border-red-100 dark:border-red-900/30'}`}>
                                  <div className="flex-1">
                                      <div className="flex items-center gap-2 flex-wrap">
                                          <h4 className="font-bold text-gray-800 dark:text-white">{item.name}</h4>
                                          <span className="text-[10px] uppercase font-bold text-gray-400 bg-gray-100 dark:bg-gray-800 px-2 py-0.5 rounded">{item.category}</span>
                                          {!suitable && (
                                              <span className="flex items-center gap-1 text-[10px] font-bold text-red-600 bg-red-100 dark:bg-red-900/50 px-2 py-0.5 rounded border border-red-200 dark:border-red-800">
                                                  <XCircle size={10} /> Avoid: {issues.join(', ')}
                                              </span>
                                          )}
                                      </div>
                                      <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{item.desc}</p>
                                      <div className="flex flex-wrap gap-2 mt-2">
                                          {tags.map((t, i) => (
                                              <span key={i} className={`text-[10px] font-bold px-2 py-0.5 rounded-full border border-transparent ${t.color}`}>
                                                  {t.text}
                                              </span>
                                          ))}
                                      </div>
                                  </div>
                                  <div className="flex gap-2 shrink-0">
                                      {(item.category === 'Veg' || item.category === 'Fruit' || item.category === 'Cereals' || item.category === 'Pulses' || item.category === 'Nuts' || item.category === 'Spice') && <div className="w-3 h-3 rounded-full border-2 border-green-600 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-green-600 rounded-full"></div></div>}
                                      {item.category === 'NonVeg' && <div className="w-3 h-3 rounded-full border-2 border-red-600 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-red-600 rounded-full"></div></div>}
                                      {(item.category === 'Dairy' || item.category === 'Bev') && <div className="w-3 h-3 rounded-full border-2 border-yellow-500 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-yellow-500 rounded-full"></div></div>}
                                  </div>
                              </div>
                          );
                      })
                  ) : (
                      <div className="text-center py-10 text-gray-400">
                          <p>No foods found matching "{searchTerm}" {showCompatibleOnly ? 'in your suitable list' : ''}.</p>
                          <p className="text-xs mt-1">Try turning off the "Suitable Only" filter to see all items.</p>
                      </div>
                  )}
                  {filteredLibrary.length > 100 && (
                      <p className="text-center text-xs text-gray-400 mt-2">Showing top 100 of {filteredLibrary.length} matches.</p>
                  )}
              </div>
          </div>
      )}

      {/* --- TAB: GUIDE --- */}
      {activeTab === 'guide' && (
          <div className="space-y-6">
              <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30">
                  <h3 className="font-bold text-blue-800 dark:text-blue-300 mb-4 flex items-center gap-2">
                      <Star size={20} /> Nutritional Guidelines (ICMR-NIN India)
                  </h3>
                  <div className="space-y-4 text-sm text-blue-900 dark:text-blue-200">
                      <div>
                          <strong className="block mb-1">Calorie Intake:</strong>
                          <p>Pregnancy requires only +350 kcal in T2 and +450 kcal in T3. Lactation requires +600 kcal. Do not "eat for two" in volume, but in quality.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Protein:</strong>
                          <p>Aim for 60-70g daily. Essential for baby's tissue growth. Include Dal/Paneer/Egg in every meal.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Iron & Folic Acid:</strong>
                          <p>Crucial to prevent anemia. Pair Iron foods (Dates, Spinach) with Vitamin C (Lemon) for absorption. Avoid Tea/Coffee 1 hour before/after meals.</p>
                      </div>
                      <div>
                          <strong className="block mb-1">Calcium:</strong>
                          <p>1200mg/day. Milk, Curd, Ragi, Sesame seeds. Do not take Iron and Calcium supplements together (they block each other).</p>
                      </div>
                  </div>
              </div>

              {comorbidities.length > 0 && (
                  <div className="bg-red-50 dark:bg-red-900/10 p-6 rounded-3xl border border-red-100 dark:border-red-900/30">
                      <h3 className="font-bold text-red-800 dark:text-red-300 mb-4 flex items-center gap-2">
                          <AlertTriangle size={20} /> Comorbidity Alerts
                      </h3>
                      <ul className="space-y-3">
                          {comorbidities.map(c => {
                              const logic = DIET_LOGIC.comorbidities[c as keyof typeof DIET_LOGIC.comorbidities];
                              if(!logic) return null;
                              return (
                                  <li key={c}>
                                      <strong className="text-red-700 dark:text-red-400 block">{logic.name}</strong>
                                      <p className="text-xs text-red-600 dark:text-red-300 mt-1">
                                          Avoid: {logic.avoid.join(', ').replace(/_/g, ' ')}. <br/>
                                          Prioritize: {logic.prioritize.join(', ').replace(/_/g, ' ')}.
                                      </p>
                                  </li>
                              );
                          })}
                      </ul>
                  </div>
              )}
          </div>
      )}

    </div>
  );
};

export type DietType = 'vegetarian' | 'eggetarian' | 'non-vegetarian';
export type AppMode = 'planning' | 'pregnant' | 'postpartum';

export interface ObstetricHistory {
  gravida: number; // Total number of times pregnant
  para: number; // Total number of viable births (>24 weeks)
  abortions: number; // Total miscarriages/abortions
  abortionsT1: number; // 1st Trimester losses (<12 weeks)
  abortionsT2: number; // 2nd Trimester losses (12-24 weeks)
  living: number; // Living children
  lastBabyCongenitalDefect: boolean; // History of congenital anomalies
  lastBabyDefectDetails?: string; // e.g., "Neural Tube Defect", "Down Syndrome"
}

export interface UserSettings {
  id: string; // Unique Profile ID

  // Core
  name: string;
  status: AppMode; // New field replacing boolean flags conceptually

  // Cycle & Fertility (Shared by Planning/Pregnant)
  lmp: string | null; // Acts as the "Active" LMP for current calculations
  pregnancyLmp?: string | null; // Stored specifically for pregnancy mode
  periodLog: string[]; // History of period start dates (ISO strings) for planning mode
  intercourseLog?: string[]; // Dates where intercourse occurred

  cycleLength: number; // Default 28

  // Physical Stats
  age?: number; // Maternal Age (CRITICAL for Risk Assessment)
  heightCm?: number; // Maternal Height
  prePregnancyWeight?: number; // Weight
  maternalBloodGroup?: string; // e.g. A+, O-

  // Partner Stats
  paternalBloodGroup?: string; // e.g. B+, AB-
  paternalHeightCm?: number; // New: For baby height prediction

  // Medical History & Risk Factors
  obstetricHistory: ObstetricHistory; // New: Parity details
  comorbidities: string[]; // List of selected condition IDs
  dietaryPreference: DietType;
  lactoseIntolerant: boolean;

  // Postpartum Specifics
  isPostpartum: boolean; // Deprecated in favor of status, kept for legacy compatibility check
  babyName?: string;
  babyGender?: 'boy' | 'girl'; 
  birthDate?: string; 
  vaccinationsDone: string[]; 

  // Pre-Pregnancy Specifics
  preConceptionChecklist?: string[]; // IDs of completed tests
  folicAcidStreak?: number;
}

export interface ProfileMeta {
  id: string;
  name: string; // Mom's name or Baby's name identifier
  status: AppMode;
  babyName?: string;
  babyGender?: 'boy' | 'girl';
  birthDate?: string;
  lastActive: string; // ISO Date
}

export interface Vaccine {
  id: string;
  name: string;
  description: string;
  dueWeekStart: number; 
  dueWeekEnd: number;
  mandatory: boolean;
  type: 'maternal' | 'baby';
}

export interface PregnancyCalculations {
  edd: Date;
  currentWeek: number;
  currentDay: number; 
  totalDays: number;
  trimester: 1 | 2 | 3;
  month: number;
  progressPercent: number;
}

export interface USGParams {
  bpd?: string; // Biparietal Diameter (Head width)
  fl?: string; // Femur Length (Thigh bone)
  ac?: string; // Abdominal Circumference
  hc?: string; // Head Circumference
  efw?: string; // Estimated Fetal Weight
  crl?: string; // Crown Rump Length (Early pregnancy)
  afi?: string; // Amniotic Fluid Index
}

export interface WeeklyInfo {
  week: number;
  babySize: string;
  babyWeight: string;
  babyLength: string;
  description: string;
  symptoms: string[];
  toDo: string[];
  notToDo: string[];
  usgParams?: USGParams; // New: Medical Reference Ranges
}

export interface ScanSchedule {
  weekStart: number;
  weekEnd: number;
  name: string;
  description: string;
  mandatory: boolean;
  completed?: boolean;
}

export interface LabTest {
  id: string;
  name: string;
  description: string;
  weekStart: number;
  weekEnd: number;
  mandatory: boolean;
  condition?: string; // If specific to a comorbidity or blood group (e.g., 'thyroid', 'rh_negative')
  category: 'Routine' | 'Special' | 'Screening';
}

export interface Medicine {
  id: string;
  name: string;
  dosage: string;
  frequency: string;
  time: string; 
  taken: boolean;
}

export interface MedicineEntry {
  category: string;
