// --- DAILY TIPS GENERATOR (1-280 Days) ---
// This provides a unique tip for every single day of pregnancy
const generateDailyTips = () => {
    const tips = [];
    const themes = [
        "Hydration: Drink at least 3L water today.",
        "Diet: Include a handful of walnuts for Omega-3.",
        "Movement: Take a 15-minute gentle walk post-dinner.",
        "Rest: Try to sleep on your left side tonight.",
        "Bonding: Talk or sing to your baby for 5 minutes.",
        "Safety: Avoid lifting anything heavier than 5kg.",
        "Medical: Check your blood pressure if you have a monitor."
    ];

    for (let i = 1; i <= 280; i++) {
        let text = "";
        const trimester = i <= 90 ? 1 : i <= 180 ? 2 : 3;
        const week = Math.ceil(i / 7);

        if (i % 7 === 0) text = `Week ${week} Complete! Take a photo of your bump today to track growth.`;
        else if (trimester === 1) {
            const t1Tips = [
                "Nausea? Try ginger tea or lemon water.",
                "Fatigue is normal. Take a 20 min nap.",
                "Avoid hot baths/saunas to protect neural tube.",
                "Folic Acid is your best friend right now.",
                "Small, frequent meals help blood sugar.",
                "Tender breasts? Wear a supportive cotton bra.",
                "Avoid raw sprouts and unpasteurized milk."
            ];
            text = t1Tips[i % t1Tips.length];
        } else if (trimester === 2) {
            const t2Tips = [
                "Iron needs increase. Eat spinach with lemon.",
                "Baby can hear! Play soothing music.",
                "Moisturize your belly to help elasticity.",
                "Leg cramps? Eat a banana for potassium.",
                "Calcium is key. Curd/Paneer/Milk daily.",
                "Feeling the flutter (Quickening)? Note the date.",
                "Back pain? Watch your posture when sitting."
            ];
            text = t2Tips[i % t2Tips.length];
        } else {
            const t3Tips = [
                "Count kicks: 10 movements in 2 hours.",
                "Swelling? Elevate your legs for 15 mins.",
                "Heartburn? Avoid spicy food before bed.",
                "Pack your hospital bag checklist items.",
                "Practice breathing exercises for labor.",
                "Visualize a smooth, positive birth.",
                "Pelvic pressure is normal as baby drops."
            ];
            text = t3Tips[i % t3Tips.length];
        }
        tips.push(text);
    }
    return tips;
};

export const DAILY_PREGNANCY_TIPS = generateDailyTips();

